mapper.select:
SELECT  FROM train_enroll e LEFT JOIN train_plan p ON e.plan_id = p.id LEFT JOIN student s ON e.stu_id = s.id

    AND e.audit_status = #{auditStatus}
    AND e.plan_id = #{planId}

ORDER BY e.create_time DESC

mapper.update:
UPDATE train_enroll
plan_id = #{planId}, stu_id = #{stuId}, enroll_time = #{enrollTime}, audit_status = #{auditStatus}, audit_user = #{auditUser}, audit_time = #{auditTime}, audit_remark = #{auditRemark}, update_time = #{updateTime},
WHERE id = #{id}
